// Cohorts now based on org size, not ACV
function getOutcomeTheme(row,mapping){
  const get=k=>(mapping[k]?(row[mapping[k]]||""):"").toString().toLowerCase();
  const txt=get("outcome")+get("product");
  if(/revenue|growth|sales|pipeline/.test(txt))return"Revenue Growth";
  if(/efficien|automat|process|cost/.test(txt))return"Operational Efficiency";
  if(/churn|retain|loyal/.test(txt))return"Customer Retention";
  if(/payroll|hr|employ|workforce/.test(txt))return"Workforce Management";
  if(/ai|ml|data|analytic/.test(txt))return"Data & AI Adoption";
  return"Strategic Transformation";
}
// Cohorts group accounts by industry. Hard-cap at MAX_COHORTS so the UI
// stays readable on imports with long-tail industry distributions — if
// more distinct industries exist, the top (MAX_COHORTS - 1) are kept as
// named cohorts and everything else rolls into a single "Other" cohort.
// No account is ever dropped. ACV is captured on the Account Review step
// as a salesperson input, not as a row attribute, so cohorts don't track it.
const MAX_COHORTS = 10;
function buildCohorts(rows,mapping){
  if(!rows.length) return [];
  const get=(row,key)=>(mapping[key]?(row[mapping[key]]||""):"").toString().trim();
  const groups={};
  rows.forEach(row=>{
    const ind      = get(row,"industry") || "",
          band     = ind || "Other",
          src      = get(row,"lead_source") || "Direct",
          outcome  = getOutcomeTheme(row,mapping),
          company  = get(row,"company"),
          product  = get(row,"product"),
          company_url   = get(row,"company_url") || "",
          employees     = get(row,"employees")   || "",
          publicPrivate = get(row,"public_private") || "",
          geography     = get(row,"geography") || "";
    if(!groups[band]) groups[band]=[];
    groups[band].push({row,ind,band,src,outcome,company,product,company_url,employees,publicPrivate,geography});
  });
  const entries = Object.entries(groups).sort(([,a],[,b])=>b.length-a.length);
  const makeCohort = (name, members, i) => ({
    id: i,
    name,
    color: COHORT_COLORS[i % COHORT_COLORS.length],
    size: members.length,
    pct: Math.round(members.length / rows.length * 100),
    topInd: [...new Set(members.map(m=>m.ind))].slice(0,3),
    topSrc: [...new Set(members.map(m=>m.src))].slice(0,2),
    topOut: [...new Set(members.map(m=>m.outcome))].slice(0,2),
    members,
  });
  if(entries.length <= MAX_COHORTS){
    return entries.map(([name,members],i)=>makeCohort(name,members,i));
  }
  const named = entries.slice(0, MAX_COHORTS - 1);
  const rest  = entries.slice(MAX_COHORTS - 1).flatMap(([,members])=>members);
  return [
    ...named.map(([name,members],i)=>makeCohort(name,members,i)),
    makeCohort("Other", rest, MAX_COHORTS - 1),
  ];
}
// ── DEAL HEALTH SCORING ──────────────────────────────────────────────────
// Rolls up RIVER gate answers + discovery capture into a numeric deal
// health score (0-100) with per-stage breakdown. Fed into post-call
// routing and forecast accuracy.
function calcConfidence(gateAnswers,riverData){
  const positive={
    r1_urgency:["Executive mandate / top-down pressure","Recent failure or incident","Budget cycle opening up"],
    i_cost:["Yes — hard numbers","Partial — sense of it but not exact"],
    v_outcome:["Yes — specific and measurable","Somewhat — directional not specific"],
    v_champion:["Yes — identified and motivated","Potential — needs equipping"],
    e_buyer:["Yes — met or confirmed","Probable — know the role"],
    e_process:["Clear — defined steps and timeline","Informal — champion can move it"],
    r2_fit:["Strong fit — ready to advance","Good fit — a few gaps"],
  };
  let score=20;
  Object.entries(positive).forEach(([gid,pos])=>{if(pos.includes(gateAnswers[gid]))score+=10;else if(gateAnswers[gid])score+=3;});
  const filled=RIVER_STAGES.flatMap(s=>s.discovery).filter(p=>riverData[p.id]?.trim().length>10).length;
  score+=filled*4;return Math.min(score,100);
}

// Per-stage deal health breakdown for RIVER scorecard
function calcDealHealth(gateAnswers,riverData){
  const stages = RIVER_STAGES.map(s => {
    let stageScore = 0, maxScore = 0;
    // Gates: 10pts each for positive, 3 for any answer
    const positiveMap = {
      r1_urgency:["Executive mandate / top-down pressure","Recent failure or incident","Budget cycle opening up"],
      r1_mustHave:["Must-have — they'd be very disappointed without a solution"],
      i_cost:["Yes — hard numbers","Partial — sense of it but not exact"],
      v_outcome:["Yes — specific and measurable","Somewhat — directional not specific"],
      v_champion:["Yes — identified and motivated","Potential — needs equipping"],
      e_buyer:["Yes — met or confirmed","Probable — know the role"],
      e_process:["Clear — defined steps and timeline","Informal — champion can move it"],
      e_committee:["3-5 = ideal range"],
      r2_fit:["Strong fit — ready to advance","Good fit — a few gaps"],
    };
    s.gates.forEach(g => {
      maxScore += 10;
      const pos = positiveMap[g.id];
      if (pos && pos.includes(gateAnswers[g.id])) stageScore += 10;
      else if (gateAnswers[g.id]) stageScore += 3;
    });
    // Discovery: 5pts each for filled fields
    s.discovery.forEach(p => {
      maxScore += 5;
      if (riverData[p.id]?.trim().length > 10) stageScore += 5;
    });
    const pct = maxScore > 0 ? Math.round(stageScore / maxScore * 100) : 0;
    const label = pct >= 75 ? "Strong" : pct >= 40 ? "Partial" : pct > 0 ? "Weak" : "Missing";
    return { stage: s.label, letter: s.letter, score: pct, label, stageScore, maxScore };
  });
  const overall = Math.round(stages.reduce((sum, s) => sum + s.score, 0) / stages.length);
  return { overall, stages };
}

function confColor(s){return s>=75?"var(--green)":s>=50?"var(--amber)":"var(--red)";}

// NOTE: No browser-side Anthropic client. All Claude calls route through
// the serverless proxies at /api/claude and /api/claude-stream — they hold
// ANTHROPIC_API_KEY server-side. Do NOT re-introduce VITE_ANTHROPIC_*; it
// would inline the key into the browser bundle.

// ── SINGLE-CALL BRIEF GENERATION: web search + synthesis in one request ────────
// Claude searches the web AND returns structured JSON in a single API call.
// This avoids the two-step coordination problem entirely.
// ── WEB SEARCH: recent news + jobs only (1 call, max 3 searches) ──────────────
// ── SAFE JSON PARSER ─────────────────────────────────────────────────────────
function safeParseJSON(text){
  try{return JSON.parse(text);}catch{ /* non-critical */ }
  const s=text.replace(/[\u2018\u2019]/g,"'").replace(/[\u201C\u201D]/g,'"').replace(/[\u2013\u2014]/g,"-").replace(/[\u2026]/g,"...").replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g,"");
  // Also strip trailing commas before arrays/objects close
  const noTrailing = s.replace(/,\s*([}\]])/g,"$1");
  try{return JSON.parse(noTrailing);}catch{ /* non-critical */ }
  let out="",inStr=false,esc=false;
  for(let i=0;i<s.length;i++){
    const ch=s[i];
    if(esc){out+=ch;esc=false;continue;}
    if(ch==="\\"){out+=ch;esc=true;continue;}
    if(inStr){
      if(ch==="\n"){out+="\\n";continue;}
      if(ch==="\r"){out+="\\r";continue;}
      if(ch==='"'){
        let j=i+1;
        while(j<s.length){if("\n\r \t".includes(s[j])){j++;continue;}if(s[j]==="\\"){j+=2;continue;}break;}
        const nxt=j<s.length?s[j]:"";
        if(nxt===","||nxt==="}"||nxt==="]"||nxt===":"||nxt===""){inStr=false;out+=ch;}
        else out+='\\"';
        continue;
      }
      out+=ch;
    }else{if(ch==='"'){inStr=true;out+=ch;}else out+=ch;}
  }
  try{return JSON.parse(out);}catch{return null;}
}


// ── JSON EXTRACTOR — brace-walking parser anchored on a key name ─────────
// Robust to narration before/after JSON and markdown code fences.
// Used by generateBrief (module scope) and component-level functions.
function extractJsonWithKey(text, anchorKey) {
  const clean = text.replace(/```(?:json)?\s*/gi, "").replace(/```/g, "");
  const anchor = clean.indexOf(`"${anchorKey}"`);
  if (anchor === -1) return null;
  let start = anchor;
  while (start > 0 && clean[start] !== "{") start--;
  if (clean[start] !== "{") return null;
  let depth = 0, inStr = false, esc = false;
  for (let i = start; i < clean.length; i++) {
    const ch = clean[i];
    if (esc) { esc = false; continue; }
    if (ch === "\\") { esc = true; continue; }
    if (ch === '"') { inStr = !inStr; continue; }
    if (inStr) continue;
    if (ch === "{") depth++;
    else if (ch === "}") {
      depth--;
      if (depth === 0) {
        try { return JSON.parse(clean.slice(start, i + 1)); }
        catch { return null; }
      }
    }
  }
  return null;
}

// ── CITATION STRIPPER — web_search returns <cite index="...">text</cite> tags ─
// Strip them globally from any AI response text before it enters state.
function stripCitations(text) {
  if (typeof text === "string") return text.replace(/<\/?cite[^>]*>/g, "");
  if (Array.isArray(text)) return text.map(stripCitations);
  if (text && typeof text === "object") {
    const out = {};
    for (const [k, v] of Object.entries(text)) out[k] = stripCitations(v);
    return out;
  }
  return text;
}

// ── AUTH TOKEN — module-level so all AI helpers can include it ─────────────
let _authToken = "";
function setAuthToken(token) { _authToken = token || ""; }
function authHeaders() {
  const h = { "Content-Type": "application/json" };
  if (_authToken) h["Authorization"] = `Bearer ${_authToken}`;
  return h;
}

// ── CAMBRIAN MAX — premium model toggle ──────────────────────────────────
// When enabled, AI calls use Opus instead of Haiku. ~15x cost but
// significantly richer output. Set by the component; read by all AI helpers.
// ── MODEL TIER STRATEGY ──────────────────────────────────────────────
// Invest in quality at the top of the funnel (ICP, research brief),
// then let rich context cascade to cheaper models downstream.
//
// Opus:   ICP Pass 1 (seller research), P3 strategy/angle, Build Target Accounts
// Sonnet: P1 overview, P2 executives, P4 solutions, P7 competitive, P8 board, P9 financial, P10 gates, RFP pipeline, ICP Pass 2
// Haiku:  P5 live, P6 roles, hypothesis, discovery, coaching, post-call, scoring
//
// Principle: accuracy first. Opus for high-judgment calls (seller research, sales angle).
// Sonnet for structured reasoning (solutions, financials, competitive). Haiku for extraction only.
const HAIKU  = "claude-haiku-4-5-20251001";
const SONNET = "claude-sonnet-4-6";
const OPUS   = "claude-opus-4-6";

// Default model for calls that don't specify — Haiku (cheapest)
function activeModel() { return HAIKU; }

// Tracking context — set before brief generation, read by claudeFetch/streamAI
let _trackingCtx = {};
function setTrackingContext(targetCompany, sellerUrl, briefType) {
  _trackingCtx = {};
  if (targetCompany) _trackingCtx["x-target-company"] = targetCompany.slice(0, 200);
  if (sellerUrl && sellerUrl !== "research-only") _trackingCtx["x-seller-url"] = sellerUrl.slice(0, 200);
  _trackingCtx["x-brief-type"] = briefType || "brief";
}
// ── VERTICAL PLAYBOOK MATCHER ────────────────────────────────────────────
// ── Smart KL cap: rank by RELEVANCE to target/seller, tier 1 = full, tier 2 = truncated ──
// Prevents 400 errors from oversized prompts while maximizing intelligence per token.
// Tier 1 (full depth, max 2): best match for TARGET industry + SELLER market
// Tier 2 (summary, max 3): remaining matches truncated to 500 chars
// Cross-cutting: always inject with size caps (exec perspectives 4KB, approval gates 3KB, others 2KB)
function _rankAndCapKls(klPairs, targetIndustry, sellerICPCtx) {
  const CROSS_CUTTING = new Set(["executivePerspectives", "approvalGates", "peHoldco", "accounting", "b2bSales", "okrKpi", "vertical"]);
  const KL_SUMMARY_LIMIT = 500;
  const crossCutLimits = { accounting: 2000, b2bSales: 2000, okrKpi: 2000, executivePerspectives: 4000, approvalGates: 3000, peHoldco: 4000 };

  const targetLow = (targetIndustry || "").toLowerCase();
  const sellerLow = [sellerICPCtx?.marketCategory, sellerICPCtx?.sellerDescription, ...(sellerICPCtx?.icp?.industries || [])].filter(Boolean).join(" ").toLowerCase();

  const active = klPairs.filter(([, v]) => v);
  const verticals = active.filter(([name]) => !CROSS_CUTTING.has(name));
  const crossCutting = active.filter(([name]) => CROSS_CUTTING.has(name));

  // Score verticals by relevance to target and seller
  const scored = verticals.map(([name, content]) => {
    const domain = name.replace(/Deep$/, "").replace(/Services$/, " services").replace(/Incentives$/, " incentives").toLowerCase();
    const targetHit = targetLow.includes(domain) ? 100 : 0;
    const sellerHit = sellerLow.includes(domain) ? 90 : 0;
    return { name, content, relevance: Math.max(targetHit, sellerHit, 10) };
  }).sort((a, b) => b.relevance - a.relevance);

  // Tier 1 (full, max 2) + Tier 2 (truncated, max 3 more)
  const verticalText = scored.slice(0, 5).map((v, i) => {
    if (i < 2) { // Tier 1: deep but capped at 6K chars to prevent 50KB KL files from dominating
      if (v.content.length <= 6000) return v.content;
      const t1 = v.content.slice(0, 6000);
      const nl1 = t1.lastIndexOf("\n");
      return (nl1 > 3000 ? t1.slice(0, nl1) : t1) + "\n[...depth-limited]\n";
    }
    const t = v.content.slice(0, KL_SUMMARY_LIMIT);
    const nl = t.lastIndexOf("\n");
    return (nl > 200 ? t.slice(0, nl) : t) + "\n[...context-limited]\n";
  }).join("");

  // Cross-cutting with size caps
  const crossText = crossCutting.map(([name, content]) => {
    const limit = crossCutLimits[name];
    if (limit && content.length > limit) {
      const t = content.slice(0, limit);
      const nl = t.lastIndexOf("\n");
      return (nl > 300 ? t.slice(0, nl) : t) + "\n[...context-limited]\n";
    }
    return content;
  }).join("");

  return verticalText + crossText;
}

// Matches vertical playbooks for BOTH the seller and the target prospect.
// Seller verticals tell you HOW to sell (your methodology, compliance, USPs).
// Target verticals tell you WHO you're selling to (their buyers, triggers, heuristics).
// Cross-vertical selling (e.g., cybersecurity → healthcare) injects both.
function _matchVerticals(text) {
  if (!text || !KL_VERTICALS || !Object.keys(KL_VERTICALS).length) return [];
  const low = text.toLowerCase();
  return Object.entries(KL_VERTICALS)
    .map(([key, v]) => {
      let score = 0;
      for (const kw of (v.keywords || [])) { if (low.includes(kw)) score += 10; }
      if (low.includes(v.name?.toLowerCase()?.split(" ")[0])) score += 5;
      return { key, v, score };
    })
    .filter(m => m.score > 0)
    .sort((a, b) => b.score - a.score);
}

function _formatVertical(v, label) {
  return [
    `\n--- ${v.name.toUpperCase()} (${label}) ---`,
    `Key buyers: ${(v.personas||[]).slice(0, 5).join(", ")}`,
    `Top triggers: ${(v.triggers||[]).slice(0, 5).join("; ")}`,
    `Disqualifiers: ${(v.disqualifiers||[]).slice(0, 4).join("; ")}`,
    `Compliance gates: ${(v.compliance||[]).slice(0, 5).join(", ")}`,
    `What matters: ${(v.usps||[]).slice(0, 4).join("; ")}`,
    `Heuristics: ${(v.heuristics||[]).slice(0, 3).join("; ")}`,
  ].join("\n");
}

function getVerticalInjection(sellerICP, targetIndustry) {
  if (!KL_VERTICALS || !Object.keys(KL_VERTICALS).length) return "";

  // Match seller verticals (how you sell)
  const sellerText = [
    sellerICP?.marketCategory,
    sellerICP?.sellerDescription,
    ...(sellerICP?.icp?.industries || []),
  ].filter(Boolean).join(" ");
  const sellerMatches = _matchVerticals(sellerText).slice(0, 2);

  // Match target verticals (who you're selling to)
  const targetMatches = targetIndustry
    ? _matchVerticals(targetIndustry).slice(0, 1)
    : [];

  // Deduplicate — if seller and target match the same vertical, show it once as "seller"
  const sellerKeys = new Set(sellerMatches.map(m => m.key));
  const uniqueTargetMatches = targetMatches.filter(m => !sellerKeys.has(m.key));

  if (!sellerMatches.length && !uniqueTargetMatches.length) return "";

  const parts = ["\nVERTICAL-SPECIFIC INTELLIGENCE:"];
  for (const { v } of sellerMatches) {
    parts.push(_formatVertical(v, "your vertical"));
  }
  for (const { v } of uniqueTargetMatches) {
    parts.push(_formatVertical(v, "prospect's vertical"));
  }
  return parts.join("\n") + "\n";
}

// ── PAYMENTS KNOWLEDGE MATCHER ─────────────────────────────────────────
// Returns the payments industry injection when the seller or target
// operates in payments, fintech, banking, card processing, or related.
const PAYMENTS_KEYWORDS = ["payment","acquiring","acquirer","interchange","iso ","merchant services","fintech","card processing","processor","payfac","issuer","issuing","credit card","debit card","pos ","point of sale","terminal","gateway","stripe","adyen","fiserv","worldpay","visa","mastercard","banking","credit union","stablecoin","embedded payments"];
// ── FAVORITES SYSTEM ────────────────────────────────────────────────────
// Star any section across the app. Persisted in session snapshots.
function StarButton({ id, type, label, content, company, step, favorites, setFavorites }) {
  const isFav = favorites.some(f => f.id === id);
  return (
    <button
      onClick={e => {
        e.stopPropagation();
        if (isFav) {
          setFavorites(prev => prev.filter(f => f.id !== id));
        } else {
          setFavorites(prev => [...prev, { id, type, label, content: (content||"").slice(0, 300), company: company||"", step: step||0, timestamp: Date.now() }]);
        }
      }}
      title={isFav ? "Remove from favorites" : "Save to favorites"}
      style={{
        background: "none", border: "none", cursor: "pointer", padding: "2px 4px",
        fontSize: 14, color: isFav ? "var(--amber)" : "var(--line-0)",
        transition: "color 0.15s, transform 0.15s",
        transform: isFav ? "scale(1.1)" : "scale(1)",
      }}
      onMouseEnter={e => { if (!isFav) e.currentTarget.style.color = "var(--amber)"; }}
      onMouseLeave={e => { if (!isFav) e.currentTarget.style.color = "var(--line-0)"; }}>
      {isFav ? "★" : "☆"}
    </button>
  );
}

function getPaymentsInjection(sellerICP, targetIndustry) {
  if (!KL_PAYMENTS) return "";
  const text = [
    sellerICP?.marketCategory,
    sellerICP?.sellerDescription,
    ...(sellerICP?.icp?.industries || []),
    targetIndustry,
  ].filter(Boolean).join(" ").toLowerCase();
  if (!text) return "";
  const hits = PAYMENTS_KEYWORDS.filter(kw => text.includes(kw));
  if (hits.length < 2) return ""; // Need 2+ keyword matches to trigger
  return "\n" + KL_PAYMENTS;
}

// ── COMPLIANCE AWARENESS INJECTION ──────────────────────────────────────
// Injects relevant compliance frameworks into prompts when the seller or
// target operates in a regulated vertical. Uses KL_COMPLIANCE data.
const COMPLIANCE_VERTICAL_KW = {
  fintech_payments: ["fintech", "payment processing", "banking", "financial services", "lending", "neobank", "processor", "acquiring", "interchange", "payfac"],
  digital_rewards_incentives: ["incentive program", "reward platform", "gift card", "employee recognition", "loyalty program", "stored-value"],
  health_wellness_b2b: ["healthcare", "wellness platform", "clinical", "hipaa", "health system", "medical device", "patient engagement", "pharma", "telehealth"],
  market_research: ["market research", "survey platform", "panel provider", "respondent"],
  real_estate: ["real estate", "homebuilder", "property developer", "land wholesaling", "reit", "btr", "build-to-rent"],
  cybersecurity: ["cybersecurity", "infosec", "soc 2", "siem", "edr", "xdr", "zero trust", "ransomware", "fedramp"],
  manufacturing: ["manufacturing", "factory", "oem", "automotive", "aerospace", "fda regulated"],
  government: ["government", "federal agency", "state government", "public sector", "govtech", "defense", "dod", "fedramp", "fisma"],
  saas_martech: ["saas platform", "software as a service", "martech", "marketing technology", "b2b software", "cloud software"],
  education: ["education", "edtech", "k-12", "higher education", "university", "school district", "lms"],
};
function getComplianceInjection(sellerICP, targetIndustry) {
  if (!KL_COMPLIANCE?.frameworks?.length) return "";
  const text = [sellerICP?.marketCategory, sellerICP?.sellerDescription, ...(sellerICP?.icp?.industries || []), targetIndustry].filter(Boolean).join(" ").toLowerCase();
  if (!text) return "";
  // Match verticals
  const matchedVerts = [];
  for (const [vId, kws] of Object.entries(COMPLIANCE_VERTICAL_KW)) {
    if (kws.some(kw => text.includes(kw))) matchedVerts.push(vId);
  }
  if (!matchedVerts.length) return "";
  // Collect primary frameworks from matched verticals
  const vMap = KL_COMPLIANCE.verticalMap || {};
  const seen = new Set();
  const frameworks = [];
  for (const vId of matchedVerts) {
    for (const fId of (vMap[vId]?.primary_frameworks || [])) {
      if (!seen.has(fId)) {
        seen.add(fId);
        const f = KL_COMPLIANCE.frameworks.find(x => x.id === fId);
        if (f) frameworks.push(f);
      }
    }
  }
  if (!frameworks.length) return "";
  const parts = ["\nCOMPLIANCE LANDSCAPE AWARENESS (Cambrian Catalyst does NOT provide compliance services — we help sellers understand the regulatory landscape their buyers operate in):"];
  for (const f of frameworks.slice(0, 5)) {
    const summary = f.talking_points?.what_reps_should_know || f.summary || "";
    parts.push(`- ${f.name}: ${summary.split(".").slice(0, 2).join(".")}.`);
  }
  parts.push("IMPORTANT: Cambrian Catalyst is a GTM consultancy, not a compliance provider. We help sellers understand and navigate compliance topics in sales conversations — not implement, audit, or certify compliance programs. Always escalate to the prospect's compliance team or qualified counsel for program design, audit scope, or legal interpretation.");
  return parts.join("\n") + "\n";
}

function getComplianceDiscovery(sellerICP, targetIndustry) {
  if (!KL_COMPLIANCE?.frameworks?.length) return "";
  const text = [sellerICP?.marketCategory, sellerICP?.sellerDescription, ...(sellerICP?.icp?.industries || []), targetIndustry].filter(Boolean).join(" ").toLowerCase();
  if (!text) return "";
  const matchedVerts = [];
  for (const [vId, kws] of Object.entries(COMPLIANCE_VERTICAL_KW)) {
    if (kws.some(kw => text.includes(kw))) matchedVerts.push(vId);
  }
  if (!matchedVerts.length) return "";
  const vMap = KL_COMPLIANCE.verticalMap || {};
  const seen = new Set();
  const qs = [];
  for (const vId of matchedVerts) {
    for (const fId of (vMap[vId]?.primary_frameworks || [])) {
      if (!seen.has(fId)) {
        seen.add(fId);
        const f = KL_COMPLIANCE.frameworks.find(x => x.id === fId);
        if (f?.discovery_questions?.length) qs.push(`${f.name}: ${f.discovery_questions[0]}`);
      }
    }
  }
  if (!qs.length) return "";
  return `\nCOMPLIANCE DISCOVERY (ask when relevant):\n${qs.slice(0, 4).map(q => `- ${q}`).join("\n")}\n`;
}

